const body = $json.body || $json;
const fecha      = body.fecha      || '';
const numeros    = body.numeros    || '';
const suma_total = body.suma_total || 0;

if (!fecha || !numeros) {
  return [{ json: { valid: false, error: 'Faltan campos fecha o numeros' } }];
}
const nums = numeros.split(',');
if (nums.length !== 20) {
  return [{ json: { valid: false, error: `Se esperan 20 numeros, llegaron ${nums.length}` } }];
}
return [{ json: { valid: true, fecha, numeros, suma_total: parseInt(suma_total) } }];

