const output = $('AI Agent').first().json.output;
const payload = $('Validar Payload').first().json;

// Verificar aciertos realmente en codigo
const sorteados = payload.numeros.split(',').map(n => n.trim().padStart(2, '0'));

function calcularAciertos(combo) {
    if (!combo) return 0;
    const nums = combo.split(',').map(n => n.trim().padStart(2, '0'));
    return nums.filter(n => sorteados.includes(n)).length;
}

function calcularPremio(ac) {
    const p = {10:'RD$25,000,000',9:'RD$150,000',8:'RD$10,000',7:'RD$1,000',6:'RD$300',5:'RD$60',0:'RD$80 (consolacion)'};
    return p[ac] || 'RD$0';
}

// Validar que las combinaciones sean distintas
let c1 = output.combinacion_1 || '';
let c2 = output.combinacion_2 || '';
let c3 = output.combinacion_3 || '';

if (c1 === c2 || c1 === c3 || c2 === c3) {
    const pool = (output.candidatos_20 || '').split(',').map(n => n.trim());
    if (pool.length >= 20) {
        c1 = pool.slice(0, 10).join(',');
        c2 = pool.slice(5, 15).join(',');
        c3 = pool.slice(10, 20).join(',');
    }
}

const ac1 = calcularAciertos(c1);
const ac2 = calcularAciertos(c2);
const ac3 = calcularAciertos(c3);
const mejor = Math.max(ac1, ac2, ac3);

return [{
    json: {
        // Resultados verificados
        aciertos_c1:         ac1,
        aciertos_c2:         ac2,
        aciertos_c3:         ac3,
        premio_c1:           calcularPremio(ac1),
        premio_c2:           calcularPremio(ac2),
        premio_c3:           calcularPremio(ac3),
        mejor_combo:         mejor === ac1 ? 'Combinacion 1' : mejor === ac2 ? 'Combinacion 2' : 'Combinacion 3',
        mejor_aciertos:      mejor,
        mejor_premio:        calcularPremio(mejor),
        // Prediccion de manana
        combinacion_1:       c1,
        combinacion_2:       c2,
        combinacion_3:       c3,
        candidatos_20:       output.candidatos_20,
        // Votacion
        estrategia_ganadora: output.estrategia_ganadora,
        votos_favor:         output.votos_favor,
        votos_total:         output.votos_total,
        razon_eleccion:      output.razon_eleccion,
        reglas_actualizadas: output.reglas_actualizadas,
        leccion_tecnica:     output.leccion,
        // Nueva estrategia
        nueva_estrategia_crear:  output.nueva_estrategia_crear || false,
        nueva_estrategia_nombre: output.nueva_estrategia_nombre || null,
        nueva_estrategia_desc:   output.nueva_estrategia_descripcion || null,
        nueva_estrategia_reglas: output.nueva_estrategia_reglas || null,
        // Para aprendizaje_ia
        fecha:               payload.fecha,
        aciertos:            mejor,
        prediccion:          c1
    }
}];
